@cython.boundscheck(False)
@cython.wraparound(False)
def gemm(int n):
    """Compute full C = A * B for n×n matrices, return trace(C)."""
    # Allocate matrices as 2D numpy arrays
    cdef double[:, :] A = np.empty((n, n), dtype=np.float64)
    cdef double[:, :] B = np.empty((n, n), dtype=np.float64)
    cdef double[:, :] C = np.zeros((n, n), dtype=np.float64)

    cdef int i, j, k
    cdef double a_ik, trace = 0.0

    # Fill A and B with the pattern
    for i in range(n):
        for j in range(n):
            A[i, j] = fmod(i + j, 100) / 10.0
            B[i, j] = fmod(i - j + n, 100) / 10.0

    # Full matrix multiply
    for i in range(n):
        for k in range(n):
            a_ik = A[i, k]
            for j in range(n):
                C[i, j] += a_ik * B[k, j]

    # Extract trace
    for i in range(n):
        trace += C[i, i]

    return trace
